INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 1, 2002, 10007, 127802, -470.0, "2023/12/22 14:59:59", 0.0, 2, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 1, "2023/09/15 15:00:00", "ヴルム");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10008, 127802, -470.0, "2023/12/22 14:59:59", 6.5, 2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 2, "2023/09/15 15:00:00", "ヴルム");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10009, 129602, -470.0, "2024/03/22 14:59:59", 0.0, 3, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 1, "2023/12/15 15:00:00", "アネモネ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10010, 129602, -470.0, "2024/03/22 14:59:59", 0.0, 3, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 2, "2023/12/15 15:00:00", "アネモネ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 1, 2002, 10011, 129701, -470.0, "2024/03/22 14:59:59", 0.0, 3, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 1, "2023/12/15 15:00:00", "ネフィ=ネラ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10012, 129701, -470.0, "2024/03/22 14:59:59", 6.2, 3, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 2, "2023/12/15 15:00:00", "ネフィ=ネラ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, 0.0, 3, 2002, 10013, 130301, -470.0, "2024/06/22 14:59:59", 3.1, 4, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 1, "2024/03/15 15:00:00", "カノン");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 0.0, 3, 2002, 10014, 130301, -470.0, "2024/06/22 14:59:59", 6.15, 4, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 2, "2024/03/15 15:00:00", "カノン");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 0.0, 2, 2002, 10015, 130401, -470.0, "2024/06/22 14:59:59", 0.0, 4, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 1, "2024/03/15 15:00:00", "ナーナ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10016, 130401, -470.0, "2024/06/22 14:59:59", 3.35, 4, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 2, "2024/03/15 15:00:00", "ナーナ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 1, 2002, 10017, 130502, -470.0, "2024/09/22 14:59:59", 0.0, 5, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 1, "2024/06/15 15:00:00", "ホウオウ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10018, 130502, -470.0, "2024/09/22 14:59:59", 3.18, 5, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 2, "2024/06/15 15:00:00", "ホウオウ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, 0.0, 4, 2002, 10019, 130503, -470.0, "2024/09/22 14:59:59", 0.0, 5, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 3, "2024/06/15 15:00:00", "ホウオウ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 0.0, 1, 2002, 10020, 123301, -470.0, "2024/09/22 14:59:59", 4.9, 5, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 1, "2024/06/15 15:00:00", "ネア");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 0.0, 1, 2002, 10021, 123301, -470.0, "2024/09/22 14:59:59", 4.8, 5, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 2, "2024/06/15 15:00:00", "ネア");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 3, 2002, 10022, 133301, -470.0, "2024/12/22 14:59:59", 4.922, 6, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 1, "2024/09/15 15:00:00", "カリザ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, 0.0, 3, 2002, 10023, 133301, -470.0, "2024/12/22 14:59:59", 9.638, 6, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 2, "2024/09/15 15:00:00", "カリザ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 0.0, 1, 2002, 10024, 133401, -470.0, "2024/12/22 14:59:59", 2.88, 6, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 1, "2024/09/15 15:00:00", "ミーア");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 5, 2002, 10025, 133401, -470.0, "2024/12/22 14:59:59", 4.818, 6, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 2, "2024/09/15 15:00:00", "ミーア");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10026, 133002, -470.0, "2025/03/22 14:59:59", 1.78, 7, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 1, "2024/12/15 15:00:00", "グレイス");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, 0.0, 1, 2002, 10027, 133002, -470.0, "2025/03/22 14:59:59", 6.15, 7, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 2, "2024/12/15 15:00:00", "グレイス");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 0.0, 6, 2002, 10028, 133102, -470.0, "2025/03/22 14:59:59", 4.28, 7, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 1, "2024/12/15 15:00:00", "ヴァイオレット");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 1, 2002, 10029, 133102, -470.0, "2025/03/22 14:59:59", 0.0, 7, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 2, "2024/12/15 15:00:00", "ヴァイオレット");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10030, 136902, -470.0, "2025/06/23 14:59:59", 5.53, 8, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 1, "2025/03/15 15:00:00", "ルルィ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, 0.0, 9, 2002, 10031, 136902, -470.0, "2025/06/23 14:59:59", 6.05, 8, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 2, "2025/03/15 15:00:00", "ルルィ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10032, 137001, -470.0, "2025/06/23 14:59:59", 0.0, 8, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 1, "2025/03/15 15:00:00", "デュラン");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10033, 137001, -470.0, "2025/06/23 14:59:59", 0.0, 8, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 2, "2025/03/15 15:00:00", "デュラン");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 0.0, 2, 2002, 10034, 135902, -470.0, "2025/09/23 14:59:59", 0.0, 9, "おう\n好きなもん持ってきな", 1, "2025/06/16 15:00:00", "サツキ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, 0.0, 1, 2002, 10035, 135902, -470.0, "2025/09/23 14:59:59", 4.935, 9, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 2, "2025/06/16 15:00:00", "サツキ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, 0.0, 2, 2002, 10036, 135802, -470.0, "2025/09/23 14:59:59", 7.441, 9, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 1, "2025/06/16 15:00:00", "ユキノ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, 0.0, 7, 2002, 10037, 135802, -470.0, "2025/09/23 14:59:59", 0.0, 9, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 2, "2025/06/16 15:00:00", "ユキノ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 0.0, 2, 2002, 10038, 130901, -470.0, "2025/12/22 14:59:59", 2.295, 10, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 1, "2025/09/16 15:00:00", "クルル");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, 0.0, 1, 2002, 10039, 130901, -470.0, "2025/12/22 14:59:59", 6.281, 10, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 2, "2025/09/16 15:00:00", "クルル");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10040, 137701, -470.0, "2025/12/22 14:59:59", 5.549, 10, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 1, "2025/09/16 15:00:00", "ヴォルガーノ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, 0.0, 3, 2002, 10041, 137701, -470.0, "2025/12/22 14:59:59", 2.64, 10, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 2, "2025/09/16 15:00:00", "ヴォルガーノ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, 0.0, 7, 2002, 10042, 132801, -470.0, "2026/03/23 11:59:59", 7.642, 11, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 1, "2025/12/15 15:00:00", "ライラエル");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 1, 2002, 10043, 132802, -470.0, "2026/03/23 11:59:59", 0.0, 11, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 2, "2025/12/15 15:00:00", "ライラエル");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 1, 2002, 10044, 134502, -470.0, "2026/03/23 11:59:59", 0.0, 11, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 1, "2025/12/15 15:00:00", "クローチェ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10045, 134501, -470.0, "2026/03/23 11:59:59", 3.72, 11, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 2, "2025/12/15 15:00:00", "クローチェ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 0.0, 2, 2002, 10046, 138201, -470.0, "2026/06/22 11:59:59", 4.991, 12, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 1, "2026/03/16 12:00:00", "ネフィ＝ネラ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, 0.0, 1, 2002, 10047, 138201, -470.0, "2026/06/22 11:59:59", 3.877, 12, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 2, "2026/03/16 12:00:00", "ネフィ＝ネラ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, 0.0, 4, 2002, 10048, 136001, -470.0, "2026/06/22 11:59:59", 1.71, 12, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 1, "2026/03/16 12:00:00", "アラクネ");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 0.0, 5, 2002, 10049, 136001, -470.0, "2026/06/22 11:59:59", 5.32, 12, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 2, "2026/03/16 12:00:00", "アラクネ");
